      { sy: 2026, sm: 6, sd: 9, ey: 2026, em: 6, ed: 30, type: '暑假' },
    ];
    for (var p = 0; p < periods.length; p++) {
      var period = periods[p];
      if (inDateRange(y, m, d, period.sy, period.sm, period.sd, period.ey, period.em, period.ed)) {
        return period.type;
      }
    }
    return '无';
  };
}

